export const nextGeneration = (cells: Cell[]): Cell[] => {
  const result: Cell[] = [];
  for (const [x, y] of cells) {
    let neighbors = 0;
    for (const [ox, oy] of cells) {
      if (ox === x && oy === y) continue;
      if (Math.abs(ox - x) <= 1 && Math.abs(oy - y) <= 1) {
        neighbors++;
      }
    }
    if (neighbors === 2 || neighbors === 3) {
      result.push([x, y]);
    }
  }
  return result;
};

