export type Cell = [number, number];

const isNeighbor = (a: Cell, b: Cell): boolean =>
  (a[0] !== b[0] || a[1] !== b[1]) &&
  Math.abs(a[0] - b[0]) <= 1 &&
  Math.abs(a[1] - b[1]) <= 1;

const countLivingNeighbors = (cell: Cell, livingCells: Cell[]): number =>
  livingCells.filter((other) => isNeighbor(cell, other)).length;

const isAlive = (cell: Cell, livingCells: Cell[]): boolean =>
  livingCells.some(([x, y]) => x === cell[0] && y === cell[1]);

export const nextGeneration = (cells: Cell[]): Cell[] => {
  const survivors = cells.filter((cell) => {
    const n = countLivingNeighbors(cell, cells);
    return n === 2 || n === 3;
  });

  const candidates: Cell[] = [];
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const candidate: Cell = [x + dx, y + dy];
        if (!isAlive(candidate, cells) && !isAlive(candidate, candidates)) {
          if (countLivingNeighbors(candidate, cells) === 3) {
            candidates.push(candidate);
          }
        }
      }
    }
  }

  return [...survivors, ...candidates];
};

